// CubeSat 3-Axis Cold-Gas RCS Attitude Hold
// Platform: Arduino Mega / STM32 Blue Pill
// Sensors: ICM-42688-P (SPI), Pressure transducer (ADC)
// Actuators: 6x solenoid via IRLZ44N MOSFETs
#include <SPI.h>

#define IMU_CS   10
#define THR_XP    2
#define THR_XN    3
#define THR_YP    4
#define THR_YN    5
#define THR_ZP    6
#define THR_ZN    7
#define PRESSURE_PIN A0
#define LED_FAULT   13

#define ICM_READ     0x80
#define ICM_PWR_REG  0x4E
#define ICM_GYRO_XH  0x25

struct PID { float kp,ki,kd,integ,prev; };
PID pidX={0.8f,0.05f,0.12f,0,0};
PID pidY={0.8f,0.05f,0.12f,0,0};
PID pidZ={0.6f,0.03f,0.10f,0,0};

enum State {INIT,ARMED,CONTROLLING,SAFE_MODE} state=INIT;
float gx,gy,gz,attX=0,attY=0,attZ=0,pressure=0;
unsigned long lastImuMs=0;

float imuReg(uint8_t reg){
  digitalWrite(IMU_CS,LOW);
  SPI.transfer(reg|ICM_READ);
  uint8_t hi=SPI.transfer(0), lo=SPI.transfer(0);
  digitalWrite(IMU_CS,HIGH);
  return (int16_t)((hi<<8)|lo)/131.0f;
}

float pidStep(PID &p, float sp, float meas, float dt){
  float e=sp-meas;
  p.integ=constrain(p.integ+e*dt,-60,60);
  float d=(e-p.prev)/dt; p.prev=e;
  return p.kp*e+p.ki*p.integ+p.kd*d;
}

void pulse(int pinP, int pinN, float cmd, float dt){
  int pw=(int)constrain(fabsf(cmd)*dt*1000.0f,0,20);
  if(pw<1) return;
  int pin=(cmd>0)?pinP:pinN;
  digitalWrite(pin,HIGH); delay(pw); digitalWrite(pin,LOW);
}

void safeMode(const char* reason){
  state=SAFE_MODE;
  for(int p:{THR_XP,THR_XN,THR_YP,THR_YN,THR_ZP,THR_ZN}) digitalWrite(p,LOW);
  digitalWrite(LED_FAULT,HIGH);
  Serial.print("FAULT,"); Serial.println(reason);
}

void setup(){
  Serial.begin(115200);
  SPI.begin();
  SPI.beginTransaction(SPISettings(8000000,MSBFIRST,SPI_MODE0));
  pinMode(IMU_CS,OUTPUT); digitalWrite(IMU_CS,HIGH);
  for(int p:{THR_XP,THR_XN,THR_YP,THR_YN,THR_ZP,THR_ZN}){
    pinMode(p,OUTPUT); digitalWrite(p,LOW);
  }
  pinMode(LED_FAULT,OUTPUT);
  // Wake ICM-42688-P
  digitalWrite(IMU_CS,LOW);
  SPI.transfer(ICM_PWR_REG&0x7F); SPI.transfer(0x0F);
  digitalWrite(IMU_CS,HIGH);
  delay(100);
  state=ARMED;
  Serial.println("STATE,ARMED");
  lastImuMs=millis();
}

void loop(){
  static unsigned long prev=0;
  unsigned long now=millis();
  float dt=(now-prev)/1000.0f;
  if(dt<0.02f) return;
  prev=now;
  if(state==SAFE_MODE) return;

  // IMU watchdog
  if(now-lastImuMs>500){ safeMode("IMU_TIMEOUT"); return; }
  gx=imuReg(ICM_GYRO_XH);
  gy=imuReg(ICM_GYRO_XH+2);
  gz=imuReg(ICM_GYRO_XH+4);
  lastImuMs=millis();

  // Pressure check (< 50 kPa = tank empty)
  pressure=analogRead(PRESSURE_PIN)*(500.0f/1023.0f);
  if(pressure<50.0f){ safeMode("LOW_PRESSURE"); return; }

  // Integrate attitude
  attX+=gx*dt; attY+=gy*dt; attZ+=gz*dt;

  if(state==ARMED){ state=CONTROLLING; Serial.println("STATE,CONTROLLING"); }

  // Cascaded PID
  float cx=pidStep(pidX,0,attX,dt);
  float cy=pidStep(pidY,0,attY,dt);
  float cz=pidStep(pidZ,0,attZ,dt);

  // Fire thrusters
  pulse(THR_XP,THR_XN,cx,dt);
  pulse(THR_YP,THR_YN,cy,dt);
  pulse(THR_ZP,THR_ZN,cz,dt);

  // UART telemetry
  Serial.print("DATA,"); Serial.print(now);
  Serial.print(","); Serial.print(attX,3);
  Serial.print(","); Serial.print(attY,3);
  Serial.print(","); Serial.print(attZ,3);
  Serial.print(","); Serial.print(cx,3);
  Serial.print(","); Serial.print(cy,3);
  Serial.print(","); Serial.print(cz,3);
  Serial.print(","); Serial.println(pressure,1);
}
